var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이...... 이건......!","JPN":"こ……これは……！","ENG":"Wait... Impossible!","TWN":"這……這是……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 내린 계시에 너 같은 존재는 없었다......!","JPN":"王より与えられた啓示に、\\n貴様のようなものは存在していない……！","ENG":"There was no being like you in the Queen's prophecy!","TWN":"王所下達的啟示裡沒有妳這樣的存在……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너는...... 너는 대체 무엇이냐?!","JPN":"貴様は……貴様はいったい何だ！？","ENG":"You... What are you?!","TWN":"妳……妳到底是什麼東西？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"너 같은 놈들은 항상 말이 많군.","JPN":"相変わらずおしゃべりな連中ね。","ENG":"Bad guys like you always talk too much.","TWN":"你們總是這麼囉嗦。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"난 말이지...... 구 관리국 시절부터 나보다 약한 녀석과 싸워 본 적이 한 번도 없어.","JPN":"私は……旧管理局時代から、\\n一度も自分より弱い奴と戦ったことなどなかった。","ENG":"You see... I've never fought anyone weaker than me since the Old Administration.","TWN":"我啊……從舊管理局時期開始，就從來沒有和比我弱的敵人戰鬥過。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"싸우면서 내 CRF 등급이 어떠니, 상대가 몇 종 침식체니 하는 걸 따지는 얼간이는 절대로 늑대의 문장을 달 수가 없으니까.","JPN":"戦いながら自分のCRF等級がどうの、相手が何種侵食体だのとのたまう\\n間抜けな理屈屋は、決して狼の紋章を冠することはできないからよ。","ENG":"Fools who weigh their CRF grades or C.O.s' categories during the fight can never wear the Seal of the Wolf.","TWN":"一邊戰鬥，一邊問別人的CRF等級多少、對方是幾類侵蝕體，像這樣的傻子是不配戴上狼之紋章的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"늑대의 문장이라고......?","JPN":"狼の紋章だと……？","ENG":"Seal of the Wolf?","TWN":"狼之紋章……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"설마, 펜릴......!","JPN":"まさか、フェンリル……！","ENG":"No, Fenrir?!","TWN":"妳該不會是，芬里爾……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"잡설이 길었군. 이만 꺼져라.","JPN":"無駄話がすぎたわね。もう消えなさい。","ENG":"Enough small talk. Now get lost.","TWN":"廢話太多了，消失吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아아아아아아아아!!","JPN":"アアアアアアアア！！","ENG":"Aaaah!!","TWN":"啊啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふぅ……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"이 정도로 지치다니, 나도 예전 같진 않네.","JPN":"この程度で疲れるなんて、昔のようにはいかないみたい。","ENG":"I'm all worn out after that? I guess it's not like the good old days anymore.","TWN":"才這種程度就精疲力盡了，看來我也不如從前了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 이 전투복, 옛날 생각이 나게 하는걸.","JPN":"でも、この戦闘服、懐かしい気分にさせてくれるわね。","ENG":"But this combat outfit does remind me of those days.","TWN":"但是這個戰鬥服倒是勾起了我的回憶。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그때는 참 철이 없었지...... 후훗, 이렇게 했었나?","JPN":"あの頃は私も青かったわ……ふふっ、こんなふうだったかしら？","ENG":"I sure was so immature back then... Heh, did it go something like this?","TWN":"那時候我還真是不懂事……呵呵，是這樣做嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"필살, 이수연 스......","JPN":"必殺、カナミ・キズナ・ス……","ENG":"Here comes a fatal blow, Lee Sooyeon Stri—","TWN":"必殺，李秀妍……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"새 전술예장은 어떤가? 너무 끼거나 불편한 곳은 없나?","JPN":"新しい戦術礼装はどうだ？\\nきつくて動きにくい部位はなかったかね？","ENG":"So how do you like the new strategic uniform? It's not too tight or uncomfortable?","TWN":"新的戰術禮裝怎麼樣？會不會太緊，有沒有不合身的地方？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"으아악! 노, 놀랐잖아요?!","JPN":"ひゃぁっ！　い、いきなり何なんですか！？","ENG":"Eeek! Y-you scared me!","TWN":"啊啊啊！我、我這不是被你嚇到了嗎？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"노크도 없이 통신을 걸다니 예, 예의가 없군요!","JPN":"ノックもなしに通信をかけるなんて、ひ、非礼にも程があります！","ENG":"You didn't even knock! How rude!","TWN":"你是不敲門就通信的嗎，太沒禮貌了！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"통신 거는데 무슨 노크를 하나. 이상한 소릴 하는군.","JPN":"通信にノックもへったくれもあるものか。妙なことを言わないでくれ。","ENG":"Who knocks during remote communication? Don't be silly.","TWN":"通信還敲什麼門，這什麼奇怪的話啊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"제, 제가 그렇다면 그런 겁니다!","JPN":"い、いちいちケチをつけないでください！","ENG":"W-whatever! If I say so, just knock!","TWN":"我、我說敲就要敲！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"아무튼...... 제법 쓸만하긴 하네요.","JPN":"とにかく……なかなか使えそうな代物です。","ENG":"Anyway... It's not bad.","TWN":"不過……確實很好用。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"이 정도라면 스승님과도 한 번 싸워 볼 만하겠어요.","JPN":"これだけの力なら師匠と一戦交えてみるのも面白そうです。","ENG":"I might even have a chance against the Master in this.","TWN":"這種程度的話，應該可以跟師父打一架了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 마음에 든다니 기쁘군.","JPN":"ハハ、気に入ってもらえて嬉しい限りだな。","ENG":"Hah hah, I'm glad you like it.","TWN":"哈哈，妳喜歡就好。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네 힘을 버티느라 주요 파츠가 동작 불능이 되어 버렸어.","JPN":"しかし、君の力に耐えていたせいか、主要パーツが作動不能に\\n陥ってしまっている。","ENG":"However, some of the key parts are now out of commission. I guess they couldn't handle your power for too long.","TWN":"但有些主要零件為了承受妳的力量故障了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"장기전은 아직 무리 같군. 돌아가면 재조정을 해 봐야겠네.","JPN":"長期戦はやはり無理そうだな。戻ったら再調整を施すとしよう。","ENG":"I suppose they're only good for shorter battles for now. I'll try tinkering with it a bit more when we're back.","TWN":"看來還不能進行持久戰，回去後得重新調整一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 그렇지. 자네를 위해 다양한 코스튬 버전도 준비해 뒀으니 기대하게.","JPN":"ああ、そうだ。\\n君のために色んなコスチュームを用意してある。\\n楽しみにしていてくれ。","ENG":"Oh, that's right. I've also prepared a variety of costume versions for you. I hope you like them.","TWN":"喔，對了，我為妳準備了很多不同裝束的版本，妳可以好好期待一下。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"......통신 끊습니다.","JPN":"……通信、切りますね。","ENG":"I'm going offline.","TWN":"……我要切斷通信了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이수연, 방금 그건......","JPN":"カナミ、今のは……","ENG":"Sooyeon... Was that...","TWN":"李秀妍，剛剛那是……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 보고 있었나?","JPN":"ああ、見てたの？","ENG":"Oh, were you watching?","TWN":"啊，妳看到了嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"놀랄 필요 없어. 펜릴 전대원이라면 누구나 이 정도는 하니까.","JPN":"驚くようなことじゃないわ。フェンリル戦隊員ならみんなこの程度はできるもの。","ENG":"No need to be so surprised. Everyone from the Fenrir Division could pull that off.","TWN":"不用這麼驚訝，是芬里爾戰隊成員的話，誰都能做到。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그건 나도 알고 있다.","JPN":"それは承知している。","ENG":"I'm aware of that.","TWN":"這我知道。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그런데 왜 예전처럼 마저 안 외치나?","JPN":"それより、なぜ以前のように最後まで叫ばなかったのだ？","ENG":"But why don't you shout the thing like you used to?","TWN":"但妳為什麼不像以前那樣喊呢？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"응? 무, 무슨 말인지 잘 모르겠는데?","JPN":"えっ？　な、何を言ってるやら、サッパリわからないんだけど？","ENG":"Huh? I-I'm not sure what you're talking about...","TWN":"唔？我、我不懂妳這是什麼意思？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"방금 전에 외치려다가 말았잖나.","JPN":"先ほどは叫び切れてなかっただろう？","ENG":"You were about to shout it just now.","TWN":"妳剛剛不是沒喊完嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"필살! 이수연 스트라......","JPN":"あれだ。必殺！　カナミ・キズナ・ストラ……","ENG":"Here comes a fatal blow! Lee Sooyeon Stri—","TWN":"必殺！李秀妍爆……"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"으아아아아!! 닥쳐!!","JPN":"ひゃああああっ！！　黙りなさい！！","ENG":"Aaaah! Shut up!","TWN":"哇啊啊啊啊啊啊！！閉嘴啊！！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};